@startuml
title UMLObject Class Diagram

class Monitor {
  o localRelays {relay.ID : Instance}
  o localAnalogOut {analogOut.ID : Instance}
}

class RS485ConfigNote {
  o modbus_interface
  o protocol
  o baudRate
  o charLen
  o parity
  o stopBits
}

class MODBUSInterface {
  o ID
}

class digitalDevice {
  o modbus_channel
}

class digitalSensor {
  o sensors {sensor_number:address}
}

class digitalModule {
  o address
}

class relayModule {
  o relays {relay_number:local_instance}
}

class analogInputModule {
  o sensors {sensor_number:local_instance}
}

class analogOuptModule {
  o output {sensor_number:local_instance}
}

digitalSensor <|-- digitalDevice
digitalModule <|-- digitalDevice
relayModule <|-- digitalModule
analogInputModule <|-- digitalModule
analogOuptModule <|-- digitalModule

@enduml
